  # Update phrase_map for better prepositions
      phrase_map["location"] = "is located in {}"

      # Build a list of clause strings, each starting with its subject
      clauses = []
      for t in triples:
          template = phrase_map.get(t.predicate)
          obj = t.object.strip('"')
          if template:
              clause = f"{t.subject} {template.format(obj)}"
          else:
              pred = t.predicate.replace('_', ' ')
              clause = f"{t.subject} {pred} {obj}"
          clauses.append(clause)

      # Join clauses into a single complex sentence
      if not clauses:
          return ""
      if len(clauses) == 1:
          sentence = clauses[0] + "."
      else:
          sentence = ", ".join(clauses[:-1]) + f", and {clauses[-1]}."
      return sentence
